#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[1015];
        scanf("%s", s);
        int sum = 0;
        for (int i = 0; s[i]; ++i) {
            if (s[i] == '-') continue;
            sum += s[i] - '0';
        }
        printf("%d\n", sum);
    }
    return 0;
}

