import sys
from functools import reduce

def sum_of_digits(number: int) -> int:
    # Convert absolute value to string, map each character to int, then reduce with addition.
    digits = map(int, str(abs(number)))
    return reduce(lambda x, y: x + y, digits, 0)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        n = int(data[i])
        out.append(str(sum_of_digits(n)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

